def acceptance_probability(delta_fitness: float, temperature: float,
                           iteration: int, max_iterations: int) -> float:
    import numpy as np
    progress = iteration / max_iterations
    # Quadratic scaling for small delta, threshold cutoff for large delta
    threshold = temperature * (1.0 - 0.9 * progress)  # decreases with iteration
    if delta_fitness > threshold:
        return 0.0
    else:
        # Quadratic penalty: probability = 1 - (delta_fitness / threshold)^2
        ratio = delta_fitness / max(threshold, 1e-10)
        prob = 1.0 - ratio * ratio
        return float(np.clip(prob, 0.0, 1.0))

def acceptance_probability(delta_fitness: float, temperature: float,
                           iteration: int, max_iterations: int) -> float:
    import numpy as np
    progress = iteration / max_iterations
    # q parameter: starts above 1 (heavy tail, exploratory) and ends below 1 (sharp, exploitative)
    q = 1.5 - 1.8 * progress  # ranges from 1.5 down to -0.3, clamped to avoid divergence
    q = np.clip(q, 0.5, 1.8)  # keep in valid range for q-exponential
    x = delta_fitness / max(temperature, 1e-10)
    # q-exponential: if q != 1, exp_q(x) = (1 + (1-q)*x)^(1/(1-q))
    if abs(q - 1.0) < 1e-10:
        prob = np.exp(-x)
    else:
        arg = 1.0 - (1.0 - q) * x
        if arg <= 0:
            prob = 0.0
        else:
            prob = arg ** (1.0 / (1.0 - q))
    return float(np.clip(prob, 0.0, 1.0))
